{
  "mode": "method",
  "tests": [
    {
      "name": "valid_navigation_elements",
      "input": {
        "page": "challenge_details",
        "user_role": "member"
      },
      "output": {
        "header": true,
        "footer": true
      },
      "notes": "Validates that both header and footer are present for a member on challenge details page."
    },
    {
      "name": "admin_navigation_elements",
      "input": {
        "page": "challenge_details",
        "user_role": "admin"
      },
      "output": {
        "header": true,
        "footer": true
      },
      "notes": "Checks that admin users also see the header and footer on challenge details."
    },
    {
      "name": "unauthenticated_user_navigation_elements",
      "input": {
        "page": "challenge_details",
        "user_role": "guest"
      },
      "output": {
        "header": true,
        "footer": true
      },
      "notes": "Ensures that unauthenticated users see the header and footer."
    },
    {
      "name": "missing_header",
      "input": {
        "page": "challenge_details",
        "user_role": "member",
        "simulate_error": "header"
      },
      "output": {
        "header": false,
        "footer": true
      },
      "notes": "Tests the case where the header is missing, expecting footer to still be present."
    },
    {
      "name": "missing_footer",
      "input": {
        "page": "challenge_details",
        "user_role": "member",
        "simulate_error": "footer"
      },
      "output": {
        "header": true,
        "footer": false
      },
      "notes": "Tests the case where the footer is missing, expecting header to still be present."
    },
    {
      "name": "navigation_elements_on_other_pages",
      "input": {
        "page": "home",
        "user_role": "member"
      },
      "output": {
        "header": true,
        "footer": true
      },
      "notes": "Validates that header and footer are present on the home page for members."
    },
    {
      "name": "challenge_details_page_load_time",
      "input": {
        "page": "challenge_details",
        "user_role": "member"
      },
      "output": {
        "load_time": "< 2s"
      },
      "notes": "Checks that the challenge details page loads within acceptable time limits."
    },
    {
      "name": "navigation_elements_for_nonexistent_page",
      "input": {
        "page": "nonexistent_page",
        "user_role": "member"
      },
      "output": {
        "header": false,
        "footer": false
      },
      "notes": "Validates that no header or footer is displayed for a nonexistent page."
    }
  ],
  "assumptions": "All users have internet access and the application is deployed correctly.",
  "notes": "Ensure to test with various user roles to validate navigation elements."
}
